import { RootAction } from 'store';

import { UserActionTypes, UserState as State } from './types';

const initialState: State = {
  userInfo: undefined,
};

export const userReducer = (state: State = initialState, action: RootAction): State => {
  switch (action.type) {
    case UserActionTypes.USER_NOT_AUTHORIZED:
      return { ...initialState, userInfo: null };

    case UserActionTypes.FETCH_USER_DATA__FAILURE:
      return { ...state, userInfo: null };

    case UserActionTypes.FETCH_USER_DATA__SUCCESS:
      return {
        ...state,
        userInfo: action.payload.data.user || null,
      };

    default:
      return state;
  }
};
