import React from 'react';

import { PageNotFound } from 'pages';
import { LogoSpinner } from 'components';

import { Props } from './types';

export class DiscordAuthCallbackPage extends React.Component<Props> {
  get urlParams() {
    return new URLSearchParams(this.props.location.search);
  }

  // Component lifecycle methods

  componentDidMount() {
    if (this.urlParams.has('code')) {
      this.props.authenticateUserWithDiscord(this.urlParams.get('code') as string);
    }
  }

  // RENDER

  render() {
    return this.urlParams.has('code') ? <LogoSpinner /> : <PageNotFound />;
  }
}
