import React from 'react';
import merge from 'classnames';

import { Props } from './types';
import './SvgIconContainer.module.scss';

export const SvgIconContainer: React.FC<Props> = props => {
  const { children, className, ...containerProps } = props;

  return (
    <span {...containerProps} className={merge('svg-icon', className)}>
      {children}
    </span>
  );
};
