import { connect } from 'react-redux';

import { RootState } from 'store';
import { selectApplicationIsLoading } from 'store/reducers/global';
import { userActions } from 'store/reducers/user';

import { RootModule as Component } from './view';

export const mapStateToProps = (state: RootState) => ({
  unexpectedError: state.global.unexpectedError,
  isApplicationLoading: selectApplicationIsLoading(state),
});

export const mapActionsToProps = {
  fetchUserData: userActions.fetchUserDataStart,
};

export const RootModule = connect(mapStateToProps, mapActionsToProps)(Component);
