import { AxiosError, AxiosPromise, AxiosResponse } from 'axios';

import { UserController } from 'controllers';

import * as Types from './types';

const fetchUserDataStart = (): Types.FetchUserDataActionStart => ({
  type: Types.UserActionTypes.FETCH_USER_DATA__START,
  apiRequest: (): AxiosPromise => UserController.fetchUserInfo(),
  followupActions: { SUCCESS: fetchUserDataSuccess, FAILURE: fetchUserDataFailure },
});

const fetchUserDataSuccess = (response: AxiosResponse): Types.FetchUserDataActionSuccess => ({
  type: Types.UserActionTypes.FETCH_USER_DATA__SUCCESS,
  payload: response,
});

const fetchUserDataFailure = (error: AxiosError): Types.FetchUserDataActionFailure => ({
  type: Types.UserActionTypes.FETCH_USER_DATA__FAILURE,
  error,
});

const authenticateUserStart = (discordCode: string): Types.AuthenticateUserActionStart => ({
  type: Types.UserActionTypes.AUTHENTICATE_USER__START,
  discordCode,
});

const authenticateUserSuccess = (response: AxiosResponse): Types.AuthenticateUserActionSuccess => ({
  type: Types.UserActionTypes.AUTHENTICATE_USER__SUCCESS,
  payload: response,
});

const authenticateUserFailure = (error: AxiosError): Types.AuthenticateUserActionFailure => ({
  type: Types.UserActionTypes.AUTHENTICATE_USER__FAILURE,
  error,
});

const userNotAuthorized = (): Types.UserNotAuthorizedAction => ({
  type: Types.UserActionTypes.USER_NOT_AUTHORIZED,
});

export const actions = {
  fetchUserDataStart,
  fetchUserDataSuccess,
  fetchUserDataFailure,
  authenticateUserStart,
  authenticateUserSuccess,
  authenticateUserFailure,
  userNotAuthorized,
};
