import { put, takeEvery } from 'redux-saga/effects';
import { AxiosResponse } from 'axios';

import { Navigation } from 'services/Navigation';
import { ROUTES } from 'router/constants';
import { AuthenticateUserActionStart, userActions, UserActionTypes } from 'store/reducers/user';
import { globalActions } from 'store/reducers/global';

import { UserController } from './UserController';

function* authenticationHandler(action: AuthenticateUserActionStart) {
  const { discordCode } = action;

  try {
    const response: AxiosResponse = yield UserController.authenticateUserWithDiscord(discordCode);

    console.log(response);

    yield put(userActions.authenticateUserSuccess(response));
  } catch (error) {
    // Process unknown or internal server errors
    if (!error.response || error.response.status >= 500) {
      yield put(globalActions.setUnexpectedError(error));
      return;
    }

    yield put(userActions.authenticateUserFailure(error));
    yield put(userActions.userNotAuthorized());

    Navigation.goTo(ROUTES.Public.Home);
  }
}

export function* AuthenticationSaga() {
  yield takeEvery(UserActionTypes.AUTHENTICATE_USER__START, authenticationHandler);
}
