import React from 'react';
import merge from 'classnames';

import { DISCORD_AUTH_FULL_URL } from 'variables';
import { Button, UserIcon } from 'components';

import { Hamburger } from '../Hamburger';
import { Props } from './types';
import styles from './NavigationBar.module.scss';

export const NavigationBar: React.FC<Props> = props => {
  const { isMobileMenuOpened, openMobileMenu, closeMobileMenu } = props;
  const onLoginButtonClick = () => {
    closeMobileMenu();
    window.location.replace(DISCORD_AUTH_FULL_URL);
  };

  return (
    <React.Fragment>
      <nav className={merge(styles.nav, { [styles.opened]: isMobileMenuOpened })}>
        <div className={styles.header}>
          <span>Guest</span>
          <Hamburger active={true} onClick={closeMobileMenu} />
        </div>

        <Button color="transparent" className={styles.login_button} onClick={onLoginButtonClick}>
          <span>Log In</span>
          <UserIcon className={styles.icon} color="white" />
        </Button>
      </nav>

      <div
        className={merge(styles.backdrop, { [styles.opened]: isMobileMenuOpened })}
        onClick={closeMobileMenu}
      />

      <Hamburger active={false} onClick={openMobileMenu} />
    </React.Fragment>
  );
};
