import { all, call, delay, put, takeEvery } from 'redux-saga/effects';
import { AxiosResponse } from 'axios';
import { AnyAction } from 'redux';

import { ApiStartAction } from 'types';
import { MINIMAL_API_PROMISE_RESOLVE_TIME } from 'variables';
import { globalActions } from 'store/reducers/global';

function* apiRequestHandler(action: ApiStartAction) {
  const { apiRequest, followupActions } = action;
  const { SUCCESS, FAILURE } = followupActions;

  try {
    // Resolve API request promise
    const [response]: [AxiosResponse] = yield all([
      call(apiRequest),
      delay(MINIMAL_API_PROMISE_RESOLVE_TIME),
    ]);

    // Call SUCCESS action with received response
    yield put(SUCCESS(response));
  } catch (error) {
    // Process unknown or internal server errors
    if (!error.response || error.response.status >= 500) {
      yield put(globalActions.setUnexpectedError(error));
      return;
    }

    // Call ERROR action with catched error
    yield put(FAILURE(error));

    // React to specific responses differently
    switch (error.response.status) {
      case 401:
        // Do something in case of "Unauthorized" response
        break;

      case 403:
        // Do something in case of "Forbidden" response
        break;

      default:
        break;
    }
  }
}

export function* ApiRequestSaga() {
  yield takeEvery((action: AnyAction): boolean => {
    // Process actions with correct signature only
    const { apiRequest, followupActions = {} } = action;
    const { SUCCESS, FAILURE } = followupActions as any;

    return !!(apiRequest && SUCCESS && FAILURE);
  }, apiRequestHandler);
}
