import React from 'react';

import { Image, Spinner } from 'components';

import { Props } from './types';
import styles from './LogoSpinner.module.scss';

export const LogoSpinner: React.FC<Props> = props =>
  props.active ? (
    <div className={styles.wrapper}>
      <div className={styles.container}>
        <Spinner size={60} />

        <Image
          src="images/application_logo@2x.png"
          alt="Poku Art Challenge loader"
          className={styles.logo}
        />
      </div>
    </div>
  ) : null;

LogoSpinner.defaultProps = {
  active: true,
} as Partial<Props>;
