import { RootAction } from 'store';

import { GlobalActionTypes, GlobalState as State } from './types';

const initialState: State = {};

export const globalReducer = (state: State = initialState, action: RootAction): State => {
  switch (action.type) {
    case GlobalActionTypes.SET_UNEXPECTED_ERROR:
      return {
        ...state,
        unexpectedError: action.error,
      };

    default:
      return state;
  }
};
