import React from 'react';
import merge from 'classnames';

import { CrossIcon, Input, SearchIcon } from 'components';

import { Props } from './types';
import styles from './SearchInput.module.scss';

export const SearchInput: React.FC<Props> = props => {
  const { active, onCrossIconClick, onSearchIconClick, className, ...inputProps } = props;

  return (
    <div className={styles.container}>
      <SearchIcon className={styles.small_search_icon} color="white" />

      <Input
        {...inputProps}
        type="text"
        color="green"
        placeholder="search"
        className={merge(styles.input, { [styles.opened]: props.value })}
      />

      {active ? (
        <CrossIcon className={styles.cross_icon} color="white" onClick={onCrossIconClick} />
      ) : (
        <SearchIcon className={styles.search_icon} color="white" onClick={onSearchIconClick} />
      )}
    </div>
  );
};
